SELECT COUNT(log_id) AS log_count
FROM process_logs
WHERE site_id = 1;

SELECT duration_seconds
FROM process_logs
WHERE duration_seconds > 300;

SELECT site_id, COUNT(*) AS total_logs
FROM process_logs
GROUP BY site_id;

SELECT site_name
FROM sites
ORDER BY site_name ASC;

SELECT duration_seconds
FROM process_logs
WHERE log_id = 0;
